import React, { useState } from "react";
import axios from "axios";

function ChatBox() {

  const [message, setMessage] = useState("");
  const [response, setResponse] = useState(null);

  const sendMessage = async () => {

    try {

      const res = await axios.post(
        "http://127.0.0.1:8000/chat",
        {
          message: message
        }
      );

      setResponse(res.data);

    } catch (err) {

      alert("Backend connection failed");

    }
  };

  return (

    <div style={{ padding: "20px" }}>

      <h1>🇮🇳 India AI Travel Planner</h1>

      <input
        type="text"
        value={message}
        placeholder="Plan Goa trip for 2 persons within 10000"
        onChange={(e) => setMessage(e.target.value)}
        style={{
          width: "70%",
          padding: "12px",
          fontSize: "16px"
        }}
      />

      <button
        onClick={sendMessage}
        style={{
          padding: "12px",
          marginLeft: "10px"
        }}
      >
        Plan Trip
      </button>

      {response && (

        <div style={{ marginTop: "30px" }}>

          {response.response ? (

            <div>

              <h2>{response.response}</h2>

            </div>

          ) : (

            <div>

              <h2>Trip Details</h2>

              <p><b>Destination:</b> {response.destination}</p>
              <p><b>Budget:</b> ₹{response.budget}</p>
              <p><b>Persons:</b> {response.persons}</p>
              <p><b>Days:</b> {response.days}</p>

              <h2>Recommended Places</h2>

              {
                response.recommendations.map((place, index) => (

                  <div
                    key={index}
                    style={{
                      border: "1px solid gray",
                      marginBottom: "20px",
                      padding: "15px",
                      borderRadius: "10px"
                    }}
                  >

                    <h3>{place.place}</h3>

                    <p><b>City:</b> {place.city}</p>
                    <p><b>State:</b> {place.state}</p>
                    <p><b>Type:</b> {place.type}</p>

                    <p><b>Hotel Cost:</b> ₹{place.hotel_cost}</p>
                    <p><b>Food Cost:</b> ₹{place.food_cost}</p>
                    <p><b>Transport Cost:</b> ₹{place.transport_cost}</p>

                    <p><b>Total Cost:</b> ₹{place.total_cost}</p>

                    <p><b>Safety Score:</b> {place.safety_score}</p>

                    <p>🚆 Railway: {place.railway_distance} km</p>
                    <p>🚌 Bus Stand: {place.bus_distance} km</p>
                    <p>✈ Airport: {place.airport_distance} km</p>

                    <a
                      href={place.google_map}
                      target="_blank"
                      rel="noreferrer"
                    >
                      View on Google Maps
                    </a>

                  </div>

                ))
              }

              <h2>Trip Itinerary</h2>

              {
                response.itinerary.map((item, index) => (

                  <div key={index}>

                    <p>
                      <b>Day {item.day}:</b> {item.plan}
                    </p>

                  </div>

                ))
              }

            </div>

          )}

        </div>

      )}

    </div>

  );
}

export default ChatBox;
